async function seededPage(items, settings = {}) {
    const { page, errors } = await freshPage();
    // Runs AFTER freshPage's clear-initScript on every navigation, marking the
    // user as onboarded so the modal never blocks test clicks.
    await page.addInitScript(() => {
        localStorage.setItem('swimlane_onboarded', 'true');
    });

    await page.goto(FILE_URL);
    await page.waitForTimeout(1200);

    const laneId = 'test-lane';
    const seedState = {
        version: 14,
        lanes:   [{ id: laneId, title: 'Lane', minimized: false, color: '#6366f1' }],
        habits: [], notes: [], projects: [],
        habitChecks: {}, diary: {}, focus: {},
        items,
        settings: { theme: 'dotted', horizonMode: 'all', habitMode: 'streak',
                    showAchievements: false, showHorizon: false, habitsMin: false, diaryMin: false,
                    ...settings }
    };

    // Write directly into the IDB that the app already opened.
    const writeResult = await page.evaluate(async (stateToSave) => {
        return await new Promise((resolve) => {
            const req = indexedDB.open('SwimlaneDB_V14', 1);
            req.onsuccess = (e) => {
                const db = e.target.result;
                try {
                    const tx = db.transaction('state', 'readwrite');
                    const putReq = tx.objectStore('state').put(stateToSave, 'appData');
                    putReq.onsuccess = () => {};
                    putReq.onerror = (err) => resolve({ ok: false, err: 'put-error: ' + err });
                    tx.oncomplete = () => { db.close(); resolve({ ok: true, lanes: stateToSave.lanes.map(l => l.id), items: stateToSave.items.length }); };
                    tx.onerror   = (err) => { db.close(); resolve({ ok: false, err: 'tx-error: ' + String(err) }); };
                } catch(e) { db.close(); resolve({ ok: false, err: 'catch: ' + e.message }); }
            };
            req.onerror = (e) => resolve({ ok: false, err: 'open-error: ' + e });
            req.onblocked = () => resolve({ ok: false, err: 'blocked' });
        });
    }, seedState);
    console.log('  [seededPage write]', JSON.stringify(writeResult));

    // Verify IDB immediately after write (before reload)
    const verifyBeforeReload = await page.evaluate(async () => {
        return new Promise(resolve => {
            const req = indexedDB.open('SwimlaneDB_V14', 1);
            req.onsuccess = e => {
                const db = e.target.result;
                const tx = db.transaction('state', 'readonly');
                tx.objectStore('state').get('appData').onsuccess = r => {
                    db.close();
                    const d = r.target.result;
                    resolve({ lanes: d?.lanes?.map(l=>l.id), items: d?.items?.length });
                };
            };
            req.onerror = () => resolve({ err: 'open-error' });
        });
    });
    console.log('  [seededPage verify before reload]', JSON.stringify(verifyBeforeReload));

    // Reload so the app boots fresh from the seeded IDB state.
    // The second initScript ensures swimlane_onboarded survives the clear.
    await page.reload();
    await page.waitForTimeout(1500);

    // Verify IDB after reload
    const verifyAfterReload = await page.evaluate(async () => {
        return new Promise(resolve => {
            const req = indexedDB.open('SwimlaneDB_V14', 1);
            req.onsuccess = e => {
                const db = e.target.result;
                const tx = db.transaction('state', 'readonly');
                tx.objectStore('state').get('appData').onsuccess = r => {
                    db.close();
                    const d = r.target.result;
                    resolve({ lanes: d?.lanes?.map(l=>l.id), items: d?.items?.length });
                };
            };
            req.onerror = () => resolve({ err: 'open-error' });
        });
    });
    console.log('  [seededPage verify after reload]', JSON.stringify(verifyAfterReload));

    return { page, errors, laneId };
}

