/**
 * tools/horizon-diag.js
 * Diagnoses why horizon inputs may not be clickable in a real browser.
 * Seeds one milestone item, opens the horizon, then:
 *   1. Reports the bounding rect of the hz-item input
 *   2. Uses elementFromPoint at the input's centre to find what is
 *      actually on top at that coordinate
