    await page.click('[data-action="toggleHorizon"]');
    await page.waitForTimeout(600);

    // ── diagnostic ───────────────────────────────────────────────────────────────
    const diag = await page.evaluate(() => {
        const input = document.querySelector('.hz-item .index-text');
        if (!input) return { error: 'no .hz-item .index-text found' };

        const rect = input.getBoundingClientRect();
        const cx = rect.left + rect.width / 2;
        const cy = rect.top  + rect.height / 2;

        // What element is actually on top at the input's centre?
        const topEl = document.elementFromPoint(cx, cy);

        // Walk ancestors of the input, collect pointer-events + z-index
        const chain = [];
        let el = input;
        while (el && el !== document.body) {
            const cs = getComputedStyle(el);
            chain.push({
                tag: el.tagName,
                id:  el.id || null,
                cls: el.className?.toString().trim().split(/\s+/).slice(0, 3).join(' '),
                pe:  cs.pointerEvents,
                zi:  cs.zIndex,
                pos: cs.position,
                ov:  cs.overflow,
            });
