            inputRect: { top: rect.top, left: rect.left, width: rect.width, height: rect.height },
            clickPoint: { x: cx, y: cy },
            topElement: topEl ? {
                tag: topEl.tagName,
                id:  topEl.id || null,
                cls: topEl.className?.toString().trim().split(/\s+/).slice(0, 4).join(' '),
                sameAsInput: topEl === input
            } : null,
            ancestorChain: chain,
        };
    });

    console.log('\n── Horizon input diagnostic ──────────────────────────────────');
    console.log(JSON.stringify(diag, null, 2));

    // ── try a real Playwright click ──────────────────────────────────────────────
    console.log('\n── Attempting real page.click on .hz-item input ──────────────');
    try {
        await page.click('.hz-item .index-text', { timeout: 3000 });
        console.log('✔  click succeeded');
    } catch (e) {
        console.log('✖  click FAILED:', e.message.split('\n')[0]);
    }

    await page.screenshot({ path: path.join(__dirname, 'horizon-diag.png') });
    console.log('\nScreenshot: tools/horizon-diag.png');
    console.log('──────────────────────────────────────────────────────────────\n');

    await browser.close();
})();

