const HTML_FILE = path.resolve(__dirname, '..', 'Swimlane_App.html');
const FILE_URL  = 'file:///' + HTML_FILE.replace(/\\/g, '/');

(async () => {
    const browser = await chromium.launch({ headless: true });
    const ctx     = await browser.newContext({ viewport: { width: 1280, height: 900 } });

    // seed one future milestone
    const tomorrow = new Date(); tomorrow.setDate(tomorrow.getDate() + 1);
    const futureDateStr = tomorrow.toISOString().split('T')[0];
    const seedState = {
        version: 14,
        lanes:   [{ id: 'diag-lane', title: 'Diag', minimized: false, color: '#6366f1' }],
        habits: [], notes: [], projects: [], habitChecks: {}, diary: {}, focus: {},
        items: [{ id: 'diag-item', laneId: 'diag-lane', dateStr: futureDateStr,
                  type: 'type-milestone', text: 'Click me', isDone: false }],
        settings: { theme: 'dotted', horizonMode: 'all', habitMode: 'streak',
                    showAchievements: false, showHorizon: false, habitsMin: false, diaryMin: false }
    };

    const seedPage = await ctx.newPage();
    await seedPage.goto(FILE_URL);
    await seedPage.waitForTimeout(600);
    await seedPage.evaluate(async (s) => {
        await new Promise(resolve => {
            const req = indexedDB.open('SwimlaneDB_V14', 1);
            req.onsuccess = e => {
                const db = e.target.result;
                const tx = db.transaction('state', 'readwrite');
                tx.objectStore('state').put(s, 'appData');
                tx.oncomplete = () => { db.close(); resolve(); };
            };
        });
    }, seedState);
    await seedPage.evaluate((seed) => {
        const orig = IDBObjectStore.prototype.put;
        IDBObjectStore.prototype.put = function(v, k) { IDBObjectStore.prototype.put = orig; return orig.call(this, seed, k); };
    }, seedState);
    await seedPage.goto('about:blank');
    await seedPage.close();

    const page = await ctx.newPage();
    await page.addInitScript(() => localStorage.setItem('swimlane_onboarded', 'true'));
    await page.goto(FILE_URL);
    await page.waitForTimeout(1500);
    await page.click('[data-action="toggleHorizon"]');
    await page.waitForTimeout(600);

