/**
 * tools/horizon-diag.js
 * Diagnoses why horizon inputs may not be clickable in a real browser.
 * Seeds one milestone item, opens the horizon, then:
 *   1. Reports the bounding rect of the hz-item input
 *   2. Uses elementFromPoint at the input's centre to find what is
 *      actually on top at that coordinate
 *   3. Reports computed pointer-events and z-index up the ancestor chain
 *   4. Tries a real Playwright click and reports success/failure
 *   5. Saves a screenshot annotated with a marker at the click point
 */

const path = require('path');
const fs   = require('fs');

function findPlaywright() {
    const cacheRoot = path.join(process.env.LOCALAPPDATA || '', 'npm-cache', '_npx');
    if (!fs.existsSync(cacheRoot)) return null;
    for (const entry of fs.readdirSync(cacheRoot)) {
        const candidate = path.join(cacheRoot, entry, 'node_modules', 'playwright');
        if (fs.existsSync(candidate)) return candidate;
    }
    return null;
}

const playwrightPath = findPlaywright();
if (!playwrightPath) { console.error('playwright not found'); process.exit(1); }
const { chromium } = require(playwrightPath);

const HTML_FILE = path.resolve(__dirname, '..', 'Swimlane_App.html');
const FILE_URL  = 'file:///' + HTML_FILE.replace(/\\/g, '/');

(async () => {
    const browser = await chromium.launch({ headless: true });
    const ctx     = await browser.newContext({ viewport: { width: 1280, height: 900 } });

    // ── seed one future milestone so the horizon has something to show ──────────
    const seedPage = await ctx.newPage();
    await seedPage.goto(FILE_URL);
    await seedPage.waitForTimeout(600);

    const tomorrow = new Date(); tomorrow.setDate(tomorrow.getDate() + 1);
    const futureDateStr = tomorrow.toISOString().split('T')[0];
    const seedState = {
        version: 14,
        lanes:   [{ id: 'diag-lane', title: 'Diag', minimized: false, color: '#6366f1' }],
        habits: [], notes: [], projects: [], habitChecks: {}, diary: {}, focus: {},
        items: [{ id: 'diag-item', laneId: 'diag-lane', dateStr: futureDateStr,
                  type: 'type-milestone', text: 'Click me', isDone: false }],
        settings: { theme: 'dotted', horizonMode: 'all', habitMode: 'streak',
                    showAchievements: false, showHorizon: false,
                    habitsMin: false, diaryMin: false }
    };

    await seedPage.evaluate(async (s) => {
        await new Promise(resolve => {
            const req = indexedDB.open('SwimlaneDB_V14', 1);
            req.onsuccess = e => {
                const db = e.target.result;
                const tx = db.transaction('state', 'readwrite');
                tx.objectStore('state').put(s, 'appData');
                tx.oncomplete = () => { db.close(); resolve(); };
            };
        });
    }, seedState);

    await seedPage.evaluate((seed) => {
        const orig = IDBObjectStore.prototype.put;
        IDBObjectStore.prototype.put = function(value, key) {
            IDBObjectStore.prototype.put = orig;
            return orig.call(this, seed, key);
        };
    }, seedState);
    await seedPage.goto('about:blank');
    await seedPage.close();

    // ── open fresh test page ─────────────────────────────────────────────────────
    const page = await ctx.newPage();
    await page.addInitScript(() => localStorage.setItem('swimlane_onboarded', 'true'));
    await page.goto(FILE_URL);
    await page.waitForTimeout(1500);

    // open horizon
    await page.click('[data-action="toggleHorizon"]');
    await page.waitForTimeout(600);

    // ── diagnostic ───────────────────────────────────────────────────────────────
    const diag = await page.evaluate(() => {
        const input = document.querySelector('.hz-item .index-text');
        if (!input) return { error: 'no .hz-item .index-text found' };

        const rect = input.getBoundingClientRect();
        const cx = rect.left + rect.width / 2;
        const cy = rect.top  + rect.height / 2;

        // What element is actually on top at the input's centre?
        const topEl = document.elementFromPoint(cx, cy);

        // Walk ancestors of the input, collect pointer-events + z-index
        const chain = [];
        let el = input;
        while (el && el !== document.body) {
            const cs = getComputedStyle(el);
            chain.push({
                tag: el.tagName,
                id:  el.id || null,
                cls: el.className?.toString().trim().split(/\s+/).slice(0, 3).join(' '),
                pe:  cs.pointerEvents,
                zi:  cs.zIndex,
                pos: cs.position,
                ov:  cs.overflow,
            });
            el = el.parentElement;
        }

        return {
            inputRect: { top: rect.top, left: rect.left, width: rect.width, height: rect.height },
            clickPoint: { x: cx, y: cy },
            topElement: topEl ? {
                tag: topEl.tagName,
                id:  topEl.id || null,
                cls: topEl.className?.toString().trim().split(/\s+/).slice(0, 4).join(' '),
                sameAsInput: topEl === input
            } : null,
            ancestorChain: chain,
        };
    });

    console.log('\n── Horizon input diagnostic ──────────────────────────────────');
    console.log(JSON.stringify(diag, null, 2));

    // ── try a real Playwright click ──────────────────────────────────────────────
    console.log('\n── Attempting real page.click on .hz-item input ──────────────');
    try {
        await page.click('.hz-item .index-text', { timeout: 3000 });
        console.log('✔  click succeeded');
    } catch (e) {
        console.log('✖  click FAILED:', e.message.split('\n')[0]);
    }

    await page.screenshot({ path: path.join(__dirname, 'horizon-diag.png') });
    console.log('\nScreenshot: tools/horizon-diag.png');
    console.log('──────────────────────────────────────────────────────────────\n');

    await browser.close();
})();

